B.a2k=new A.bn(8,"Espejo de Cuadr\xedcula","Identifica la imagen que representa el reflejo exacto de la primera cuadr\xedcula en el espejo central.","assets/figuras_psicometrico/simetria/q08_secuencia.svg",B.WA,"B","El reflejo en el espejo invierte las posiciones laterales. La opci\xf3n B representa la transformaci\xf3n sim\xe9trica correcta de los elementos internos.","simetria")
