B.a2w=new A.bn(56,"Cerillos: Romanos I","Corrige VI - IV = IX moviendo un cerillo.","assets/figuras_psicometrico/cerillos/cerillo_14.svg",B.ay,"B",'Convierte el "-" en "+" y el IX en X. VI + IV = X.',"logica")
B.a2n=new A.bn(57,"Cerillos: Romanos II","Mueve un cerillo en XII / II = VII.","assets/figuras_psicometrico/cerillos/cerillo_15.svg",B.ay,"C","Convierte el XII en XIV moviendo un cerillo. XIV / II = VII.","logica")
B.a1Z=new A.bn(58,"Cerillos: Romanos III","Mueve un cerillo en X + X = L.","assets/figuras_psicometrico/cerillos/cerillo_16.svg",B.ay,"D","Mueve los cerillos de la L para formar XX. X + X = XX.","logica")
B.a2u=new A.bn(59,"Cerillos: Romanos IV","Corrige IV + V = VI moviendo un cerillo.","assets/figuras_psicometrico/cerillos/cerillo_17.svg",B.ay,"A","Mueve un cerillo del V para convertirlo en I, y ponlo en el resultado. IV + I = V.","logica")
B.a1H=new A.bn(60,"Cerillos: Romanos V","Corrige L + I = C moviendo un cerillo.","assets/figuras_psicometrico/cerillos/cerillo_18.svg",B.ay,"B","Convierte el I en L moviendo cerillos adicionales? No, L + L = C.","logica")
B.a2l=new A.bn(61,"Cerillos: Triple Nueve","Corrige 9 + 9 = 9 moviendo un cerillo.","assets/figuras_psicometrico/cerillos/cerillo_19.svg",B.ay,"C",'Convierte el "+" en "-" y el segundo 9 en 0. 9 - 0 = 9.',"logica")
B.a2c=new A.bn(62,"Cerillos: Docena","Corrige 6 + 1 = 12 moviendo un cerillo.","assets/figuras_psicometrico/cerillos/cerillo_20.svg",B.ay,"D","Convierte el 1 en 6 moviendo un cerillo del 12? No, 6 + 6 = 12.","logica")
B.a2i=new A.bn(63,"Cerillos: El Ocho Maestro","Corrige 8 + 8 = 10 moviendo un cerillo.",u.P,B.ay,"B","Convierte el segundo 8 en un 2 moviendo cerillos estrat\xe9gicamente. 8 + 2 = 10.","logica")
B.a26=new A.bn(64,"Cerillos: Resta T\xe1ctica","Corrige 3 + 2 = 5 moviendo un cerillo para convertirlo en una resta v\xe1lida.",u._,B.ay,"A",'Mueve el cerillo del "+" al resultado 5 para hacerlo 3? No, 5 - 2 = 3.',"logica")
B.a1I=new A.bn(65,"Cerillos: Multiplicaci\xf3n Fantasma","Mueve un cerillo en 7 x 1 = 1 moviendo la diagonal del 7.",u.Y,B.ay,"E",'Convierte el "x" en "-" y el 7 en 1. 1 - 1 = 0? No, 1 x 1 = 1.',"logica")
